      languagesSpoken: ["english", "sinhala"],
      consultationTypes: ["in_person", "online"],
      hospitalIds: ["hosp-3"],
      consultationFee: 1800,
      onlineConsultationFee: 1500,
      status: "verified",
      isAvailable: true,
      averageRating: 4.6,
      totalReviews: 45,
      totalAppointments: 450,
    },
  ];
