import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { 
  Calendar,
  Clock,
  Plus,
  Trash2,
  ChevronLeft,
  ChevronRight,
  AlertCircle,
  Video,
  Building2,
  Lock,
  Unlock
} from "lucide-react";
import { format, addDays, startOfWeek, addWeeks, subWeeks, isSameDay, parseISO, isToday } from "date-fns";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { LoadingPage, LoadingSpinner } from "@/components/ui/loading-spinner";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { useToast } from "@/hooks/use-toast";
import { apiRequest, queryClient } from "@/lib/queryClient";
import type { AppointmentSlot, DoctorProfile } from "@shared/schema";

export default function DoctorSchedule() {
  const { toast } = useToast();
  const [currentWeekStart, setCurrentWeekStart] = useState(startOfWeek(new Date(), { weekStartsOn: 1 }));
  const [selectedDate, setSelectedDate] = useState<Date | null>(null);
  const [addSlotDialogOpen, setAddSlotDialogOpen] = useState(false);
  const [newSlot, setNewSlot] = useState({
    startTime: "09:00",
    endTime: "09:30",
    consultationType: "in_person" as "in_person" | "online",
  });

  const { data: profile } = useQuery<DoctorProfile>({
    queryKey: ["/api/doctor/profile"],
  });

  const startDate = format(currentWeekStart, "yyyy-MM-dd");
  const endDate = format(addDays(currentWeekStart, 6), "yyyy-MM-dd");

  const { data: slots = [], isLoading, isError } = useQuery<AppointmentSlot[]>({
    queryKey: ["/api/doctor/slots", startDate, endDate],
    queryFn: async () => {
      const res = await fetch(`/api/doctor/slots?startDate=${startDate}&endDate=${endDate}`, {
        headers: {
          Authorization: `Bearer ${localStorage.getItem("token")}`,
        },
      });
      if (!res.ok) throw new Error("Failed to load slots");
      return res.json();
    },
    enabled: !!profile,
  });

  const createSlotMutation = useMutation({
    mutationFn: (data: { date: string; startTime: string; endTime: string; consultationType: string }) =>
      apiRequest("POST", "/api/slots", {
        ...data,
        doctorId: profile?.id,
        hospitalId: profile?.hospitalIds?.[0],
      }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/doctor/slots"] });
      setAddSlotDialogOpen(false);
      toast({ title: "Slot created successfully" });
    },
    onError: () => {
      toast({ title: "Failed to create slot", variant: "destructive" });
    },
  });

  const blockSlotMutation = useMutation({
    mutationFn: (slotId: string) => apiRequest("PATCH", `/api/slots/${slotId}/block`),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/doctor/slots"] });
      toast({ title: "Slot blocked" });
    },
    onError: () => {
      toast({ title: "Failed to block slot", variant: "destructive" });
    },
  });

  const unblockSlotMutation = useMutation({
    mutationFn: (slotId: string) => apiRequest("PATCH", `/api/slots/${slotId}/unblock`),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/doctor/slots"] });
      toast({ title: "Slot unblocked" });
    },
    onError: () => {
      toast({ title: "Failed to unblock slot", variant: "destructive" });
    },
  });

  const deleteSlotMutation = useMutation({
    mutationFn: (slotId: string) => apiRequest("DELETE", `/api/slots/${slotId}`),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/doctor/slots"] });
      toast({ title: "Slot deleted" });
    },
    onError: () => {
      toast({ title: "Failed to delete slot", variant: "destructive" });
    },
  });

  const weekDays = Array.from({ length: 7 }, (_, i) => addDays(currentWeekStart, i));

  const getSlotsForDate = (date: Date) => {
    const dateStr = format(date, "yyyy-MM-dd");
    return slots.filter(s => s.date === dateStr).sort((a, b) => a.startTime.localeCompare(b.startTime));
  };

  const handleAddSlot = () => {
    if (!selectedDate) return;
    createSlotMutation.mutate({
      date: format(selectedDate, "yyyy-MM-dd"),
      startTime: newSlot.startTime,
      endTime: newSlot.endTime,
      consultationType: newSlot.consultationType,
    });
  };

  const timeSlots = [
    "08:00", "08:30", "09:00", "09:30", "10:00", "10:30", "11:00", "11:30",
    "12:00", "12:30", "13:00", "13:30", "14:00", "14:30", "15:00", "15:30",
    "16:00", "16:30", "17:00", "17:30", "18:00"
  ];

  if (isLoading) {
    return <LoadingPage message="Loading schedule..." />;
  }

  if (isError) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] gap-4">
        <AlertCircle className="h-12 w-12 text-destructive" />
        <p className="text-muted-foreground">Failed to load schedule. Please try again.</p>
        <Button onClick={() => window.location.reload()}>Retry</Button>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl md:text-3xl font-heading font-bold" data-testid="text-page-title">
            Schedule Management
          </h1>
          <p className="text-muted-foreground">
            Manage your appointment slots and availability
          </p>
        </div>
      </div>

      <Card>
        <CardHeader className="flex flex-row items-center justify-between gap-4">
          <CardTitle className="flex items-center gap-2">
            <Calendar className="h-5 w-5" />
            Weekly Schedule
          </CardTitle>
          <div className="flex items-center gap-2">
            <Button
              variant="outline"
              size="icon"
              onClick={() => setCurrentWeekStart(subWeeks(currentWeekStart, 1))}
              data-testid="button-prev-week"
            >
              <ChevronLeft className="h-4 w-4" />
            </Button>
            <span className="text-sm font-medium min-w-[180px] text-center">
              {format(currentWeekStart, "MMM d")} - {format(addDays(currentWeekStart, 6), "MMM d, yyyy")}
            </span>
            <Button
              variant="outline"
              size="icon"
              onClick={() => setCurrentWeekStart(addWeeks(currentWeekStart, 1))}
              data-testid="button-next-week"
            >
              <ChevronRight className="h-4 w-4" />
            </Button>
          </div>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-7 gap-2">
            {weekDays.map((day) => {
              const daySlots = getSlotsForDate(day);
              const isSelected = selectedDate && isSameDay(day, selectedDate);
              const isPastDay = day < new Date() && !isToday(day);

              return (
                <div 
                  key={day.toISOString()}
                  className={`border rounded-lg p-3 min-h-[200px] ${
                    isToday(day) ? "border-primary bg-primary/5" : ""
                  } ${isSelected ? "ring-2 ring-primary" : ""} ${
                    isPastDay ? "opacity-50" : ""
                  }`}
                  data-testid={`day-${format(day, "yyyy-MM-dd")}`}
                >
                  <div className="text-center mb-2">
                    <p className="text-xs text-muted-foreground uppercase">
                      {format(day, "EEE")}
                    </p>
                    <p className={`text-lg font-semibold ${
                      isToday(day) ? "text-primary" : ""
                    }`}>
                      {format(day, "d")}
                    </p>
                  </div>

                  <div className="space-y-1">
                    {daySlots.slice(0, 4).map((slot) => (
                      <div
                        key={slot.id}
                        className={`text-xs p-1.5 rounded flex items-center justify-between gap-1 ${
                          slot.isBlocked 
                            ? "bg-muted text-muted-foreground line-through" 
                            : slot.isBooked
                              ? "bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300"
                              : "bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-300"
                        }`}
                        data-testid={`slot-${slot.id}`}
                      >
                        <span className="flex items-center gap-1">
                          {slot.consultationType === "online" ? (
                            <Video className="h-3 w-3" />
                          ) : (
                            <Building2 className="h-3 w-3" />
                          )}
                          {slot.startTime}
                        </span>
                        {!slot.isBooked && !isPastDay && (
                          <Button
                            variant="ghost"
                            size="icon"
                            className="h-4 w-4 p-0"
                            onClick={() => slot.isBlocked 
                              ? unblockSlotMutation.mutate(slot.id)
                              : blockSlotMutation.mutate(slot.id)
                            }
                          >
                            {slot.isBlocked ? (
                              <Unlock className="h-3 w-3" />
                            ) : (
                              <Lock className="h-3 w-3" />
                            )}
                          </Button>
                        )}
                      </div>
                    ))}
                    {daySlots.length > 4 && (
                      <p className="text-xs text-muted-foreground text-center">
                        +{daySlots.length - 4} more
                      </p>
                    )}
                    {daySlots.length === 0 && !isPastDay && (
                      <p className="text-xs text-muted-foreground text-center py-2">
                        No slots
                      </p>
                    )}
                  </div>

                  {!isPastDay && (
                    <Button
                      variant="ghost"
                      size="sm"
                      className="w-full mt-2 text-xs"
                      onClick={() => {
                        setSelectedDate(day);
                        setAddSlotDialogOpen(true);
                      }}
                      data-testid={`button-add-slot-${format(day, "yyyy-MM-dd")}`}
                    >
                      <Plus className="h-3 w-3 mr-1" />
                      Add
                    </Button>
                  )}
                </div>
              );
            })}
          </div>
        </CardContent>
      </Card>

      <div className="grid md:grid-cols-2 gap-6">
        <Card>
          <CardHeader>
            <CardTitle>Slot Legend</CardTitle>
          </CardHeader>
          <CardContent className="space-y-3">
            <div className="flex items-center gap-3">
              <div className="w-4 h-4 rounded bg-green-100 dark:bg-green-900/30 border border-green-300" />
              <span className="text-sm">Available slot</span>
            </div>
            <div className="flex items-center gap-3">
              <div className="w-4 h-4 rounded bg-blue-100 dark:bg-blue-900/30 border border-blue-300" />
              <span className="text-sm">Booked slot</span>
            </div>
            <div className="flex items-center gap-3">
              <div className="w-4 h-4 rounded bg-muted border" />
              <span className="text-sm">Blocked slot</span>
            </div>
            <div className="flex items-center gap-3">
              <Video className="h-4 w-4 text-muted-foreground" />
              <span className="text-sm">Online consultation</span>
            </div>
            <div className="flex items-center gap-3">
              <Building2 className="h-4 w-4 text-muted-foreground" />
              <span className="text-sm">In-person consultation</span>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle>Quick Stats</CardTitle>
          </CardHeader>
          <CardContent className="space-y-3">
            <div className="flex items-center justify-between">
              <span className="text-sm text-muted-foreground">Total Slots This Week</span>
              <Badge variant="secondary">{slots.length}</Badge>
            </div>
            <div className="flex items-center justify-between">
              <span className="text-sm text-muted-foreground">Available</span>
              <Badge className="bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-300">
                {slots.filter(s => !s.isBooked && !s.isBlocked).length}
              </Badge>
            </div>
            <div className="flex items-center justify-between">
              <span className="text-sm text-muted-foreground">Booked</span>
              <Badge className="bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300">
                {slots.filter(s => s.isBooked).length}
              </Badge>
            </div>
            <div className="flex items-center justify-between">
              <span className="text-sm text-muted-foreground">Blocked</span>
              <Badge variant="outline">
                {slots.filter(s => s.isBlocked).length}
              </Badge>
            </div>
          </CardContent>
        </Card>
      </div>

      <Dialog open={addSlotDialogOpen} onOpenChange={setAddSlotDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Add New Slot</DialogTitle>
            <DialogDescription>
              Create a new appointment slot for {selectedDate ? format(selectedDate, "MMMM d, yyyy") : "selected date"}
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label>Start Time</Label>
                <Select
                  value={newSlot.startTime}
                  onValueChange={(value) => setNewSlot(prev => ({ ...prev, startTime: value }))}
                >
                  <SelectTrigger data-testid="select-start-time">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {timeSlots.map((time) => (
                      <SelectItem key={time} value={time}>{time}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label>End Time</Label>
                <Select
                  value={newSlot.endTime}
                  onValueChange={(value) => setNewSlot(prev => ({ ...prev, endTime: value }))}
                >
                  <SelectTrigger data-testid="select-end-time">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {timeSlots.map((time) => (
                      <SelectItem key={time} value={time}>{time}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>
            <div className="space-y-2">
              <Label>Consultation Type</Label>
              <Select
                value={newSlot.consultationType}
                onValueChange={(value: "in_person" | "online") => 
                  setNewSlot(prev => ({ ...prev, consultationType: value }))
                }
              >
                <SelectTrigger data-testid="select-consultation-type">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="in_person">
                    <span className="flex items-center gap-2">
                      <Building2 className="h-4 w-4" />
                      In Person
                    </span>
                  </SelectItem>
                  <SelectItem value="online">
                    <span className="flex items-center gap-2">
                      <Video className="h-4 w-4" />
                      Online
                    </span>
                  </SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setAddSlotDialogOpen(false)}>
              Cancel
            </Button>
            <Button
              onClick={handleAddSlot}
              disabled={createSlotMutation.isPending}
              data-testid="button-create-slot"
            >
              {createSlotMutation.isPending && <LoadingSpinner size="sm" className="mr-2" />}
              Create Slot
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

client/src/pages/admin/specializations.t.content:
import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { 
  Plus, 
  AlertCircle,
  Edit,
  Trash2,
  Activity,
  Leaf,
  Heart,
  Sparkles,
  Scissors,
  Eye,
  Baby,
  Users,
  Brain
} from "lucide-react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { LoadingPage } from "@/components/ui/loading-spinner";
import { useToast } from "@/hooks/use-toast";
import { apiRequest, queryClient } from "@/lib/queryClient";
import type { Specialization } from "@shared/schema";

const iconOptions = [
  { value: "Leaf", label: "Leaf", icon: Leaf },
  { value: "Heart", label: "Heart", icon: Heart },
  { value: "Sparkles", label: "Sparkles", icon: Sparkles },
  { value: "Scissors", label: "Scissors", icon: Scissors },
  { value: "Eye", label: "Eye", icon: Eye },
  { value: "Baby", label: "Baby", icon: Baby },
  { value: "Users", label: "Users", icon: Users },
  { value: "Brain", label: "Brain", icon: Brain },
  { value: "Activity", label: "Activity", icon: Activity },
];

const getIconComponent = (iconName: string) => {
  const icon = iconOptions.find(i => i.value === iconName);
  return icon ? icon.icon : Activity;
};

export default function AdminSpecializationsPage() {
  const { toast } = useToast();
  const [showAddDialog, setShowAddDialog] = useState(false);
  const [showEditDialog, setShowEditDialog] = useState(false);
  const [showDeleteDialog, setShowDeleteDialog] = useState(false);
  const [selectedSpec, setSelectedSpec] = useState<Specialization | null>(null);
  const [formData, setFormData] = useState({ name: "", description: "", icon: "Leaf" });

  const { data: specializations = [], isLoading, isError } = useQuery<Specialization[]>({
    queryKey: ["/api/specializations"],
  });

  const createMutation = useMutation({
    mutationFn: (data: { name: string; description: string; icon: string }) => 
      apiRequest("POST", "/api/specializations", data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/specializations"] });
      toast({
        title: "Specialization Created",
        description: "The specialization has been created successfully.",
      });
      setShowAddDialog(false);
      setFormData({ name: "", description: "", icon: "Leaf" });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to create specialization. Please try again.",
        variant: "destructive",
      });
    },
  });

  const updateMutation = useMutation({
    mutationFn: ({ id, data }: { id: string; data: { name: string; description: string; icon: string } }) => 
      apiRequest("PUT", `/api/admin/specializations/${id}`, data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/specializations"] });
      toast({
        title: "Specialization Updated",
        description: "The specialization has been updated successfully.",
      });
      setShowEditDialog(false);
      setSelectedSpec(null);
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to update specialization. Please try again.",
        variant: "destructive",
      });
    },
  });

  const deleteMutation = useMutation({
    mutationFn: (id: string) => 
      apiRequest("DELETE", `/api/admin/specializations/${id}`),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/specializations"] });
      toast({
        title: "Specialization Deleted",
        description: "The specialization has been deleted successfully.",
      });
      setShowDeleteDialog(false);
      setSelectedSpec(null);
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to delete specialization. It may be in use by doctors.",
        variant: "destructive",
      });
    },
  });

  const handleEdit = (spec: Specialization) => {
    setSelectedSpec(spec);
    setFormData({
      name: spec.name,
      description: spec.description || "",
      icon: spec.icon || "Leaf",
    });
    setShowEditDialog(true);
  };

  const handleDelete = (spec: Specialization) => {
    setSelectedSpec(spec);
    setShowDeleteDialog(true);
  };

  if (isLoading) {
    return <LoadingPage message="Loading specializations..." />;
  }

  if (isError) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] gap-4">
        <AlertCircle className="h-12 w-12 text-destructive" />
        <p className="text-muted-foreground">Failed to load specializations. Please try again.</p>
        <Button onClick={() => window.location.reload()}>Retry</Button>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl md:text-3xl font-heading font-bold">Specializations</h1>
          <p className="text-muted-foreground">Manage Ayurvedic medical specializations</p>
        </div>
        <Button onClick={() => setShowAddDialog(true)} data-testid="button-add">
          <Plus className="h-4 w-4 mr-2" />
          Add Specialization
        </Button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {specializations.map((spec) => {
          const IconComponent = getIconComponent(spec.icon || "Activity");
          return (
            <Card key={spec.id} className="hover-elevate" data-testid={`card-spec-${spec.id}`}>
              <CardContent className="p-4">
                <div className="flex items-start justify-between gap-3">
                  <div className="flex items-start gap-3">
                    <div className="p-2 rounded-lg bg-primary/10">
                      <IconComponent className="h-5 w-5 text-primary" />
                    </div>
                    <div className="min-w-0">
                      <h3 className="font-semibold">{spec.name}</h3>
                      <p className="text-sm text-muted-foreground line-clamp-2 mt-1">
                        {spec.description || "No description"}
                      </p>
                    </div>
                  </div>
                  <div className="flex gap-1 shrink-0">
                    <Button 
                      variant="ghost" 
                      size="icon"
                      onClick={() => handleEdit(spec)}
                      data-testid={`button-edit-${spec.id}`}
                    >
                      <Edit className="h-4 w-4" />
                    </Button>
                    <Button 
                      variant="ghost" 
                      size="icon"
                      className="text-destructive hover:text-destructive"
                      onClick={() => handleDelete(spec)}
                      data-testid={`button-delete-${spec.id}`}
                    >
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  </div>
                </div>
              </CardContent>
            </Card>
          );
        })}

        {specializations.length === 0 && (
          <div className="col-span-full">
            <Card>
              <CardContent className="flex flex-col items-center justify-center py-12">
                <Activity className="h-12 w-12 text-muted-foreground mb-4" />
                <h3 className="font-semibold mb-1">No specializations yet</h3>
                <p className="text-muted-foreground text-sm mb-4">
                  Add your first specialization to get started
                </p>
                <Button onClick={() => setShowAddDialog(true)}>
                  <Plus className="h-4 w-4 mr-2" />
                  Add Specialization
                </Button>
              </CardContent>
            </Card>
          </div>
        )}
      </div>

      <Dialog open={showAddDialog} onOpenChange={setShowAddDialog}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Add Specialization</DialogTitle>
            <DialogDescription>
              Create a new Ayurvedic medical specialization
            </DialogDescription>
          </DialogHeader>

          <div className="grid gap-4 py-4">
            <div className="grid gap-2">
              <Label htmlFor="name">Name</Label>
              <Input
                id="name"
                placeholder="e.g., Panchakarma"
                value={formData.name}
                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                data-testid="input-name"
              />
            </div>
            <div className="grid gap-2">
              <Label htmlFor="description">Description</Label>
              <Textarea
                id="description"
                placeholder="Brief description of the specialization..."
                value={formData.description}
                onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                rows={3}
                data-testid="input-description"
              />
            </div>
            <div className="grid gap-2">
              <Label>Icon</Label>
              <Select value={formData.icon} onValueChange={(value) => setFormData({ ...formData, icon: value })}>
                <SelectTrigger data-testid="select-icon">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {iconOptions.map((option) => (
                    <SelectItem key={option.value} value={option.value}>
                      <div className="flex items-center gap-2">
                        <option.icon className="h-4 w-4" />
                        <span>{option.label}</span>
                      </div>
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          </div>

          <DialogFooter>
            <Button variant="outline" onClick={() => setShowAddDialog(false)}>
              Cancel
            </Button>
            <Button 
              onClick={() => createMutation.mutate(formData)}
              disabled={!formData.name || createMutation.isPending}
              data-testid="button-submit"
            >
              Create Specialization
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <Dialog open={showEditDialog} onOpenChange={setShowEditDialog}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Edit Specialization</DialogTitle>
            <DialogDescription>
              Update the specialization details
            </DialogDescription>
          </DialogHeader>

          <div className="grid gap-4 py-4">
            <div className="grid gap-2">
              <Label htmlFor="edit-name">Name</Label>
              <Input
                id="edit-name"
                value={formData.name}
                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                data-testid="input-edit-name"
              />
            </div>
            <div className="grid gap-2">
              <Label htmlFor="edit-description">Description</Label>
              <Textarea
                id="edit-description"
                value={formData.description}
                onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                rows={3}
                data-testid="input-edit-description"
              />
            </div>
            <div className="grid gap-2">
              <Label>Icon</Label>
              <Select value={formData.icon} onValueChange={(value) => setFormData({ ...formData, icon: value })}>
                <SelectTrigger data-testid="select-edit-icon">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {iconOptions.map((option) => (
                    <SelectItem key={option.value} value={option.value}>
                      <div className="flex items-center gap-2">
                        <option.icon className="h-4 w-4" />
                        <span>{option.label}</span>
                      </div>
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          </div>

          <DialogFooter>
            <Button variant="outline" onClick={() => setShowEditDialog(false)}>
              Cancel
            </Button>
            <Button 
              onClick={() => {
                if (selectedSpec) {
                  updateMutation.mutate({ id: selectedSpec.id, data: formData });
                }
              }}
              disabled={!formData.name || updateMutation.isPending}
              data-testid="button-update"
            >
              Update Specialization
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <AlertDialog open={showDeleteDialog} onOpenChange={setShowDeleteDialog}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Delete Specialization</AlertDialogTitle>
            <AlertDialogDescription>
              Are you sure you want to delete "{selectedSpec?.name}"? This action cannot be undone.
              Doctors with this specialization will need to update their profiles.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction
              onClick={() => {
                if (selectedSpec) {
                  deleteMutation.mutate(selectedSpec.id);
                }
              }}
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
              data-testid="button-confirm-delete"
            >
              Delete
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

client/src/pages/patient/appointments.ts.content:
import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { format, parseISO, isAfter, isBefore } from "date-fns";
import {
  Calendar,
  Clock,
  Video,
  Building2,
  Search,
  Filter,
  X,
  AlertCircle,
  CheckCircle,
  XCircle,
  MoreVertical,
  Phone,
  MapPin,
  ChevronRight,
} from "lucide-react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { LoadingPage } from "@/components/ui/loading-spinner";
import { StatusBadge } from "@/components/ui/status-badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { useToast } from "@/hooks/use-toast";
import { apiRequest, queryClient } from "@/lib/queryClient";
import type { AppointmentWithDetails } from "@shared/schema";
import { AppointmentStatus, ConsultationType } from "@shared/schema";

export default function PatientAppointmentsPage() {
  const { toast } = useToast();
  const [searchQuery, setSearchQuery] = useState("");
  const [statusFilter, setStatusFilter] = useState<string>("all");
  const [typeFilter, setTypeFilter] = useState<string>("all");
  const [selectedAppointment, setSelectedAppointment] = useState<AppointmentWithDetails | null>(null);
  const [cancelDialogOpen, setCancelDialogOpen] = useState(false);
  const [cancelReason, setCancelReason] = useState("");
  const [detailsDialogOpen, setDetailsDialogOpen] = useState(false);

  const { data: appointments = [], isLoading, isError } = useQuery<AppointmentWithDetails[]>({
    queryKey: ["/api/appointments"],
    staleTime: 60 * 1000,
  });

  const cancelMutation = useMutation({
    mutationFn: async ({ id, reason }: { id: string; reason: string }) => {
      const response = await apiRequest("PATCH", `/api/appointments/${id}/cancel`, { reason });
      return response;
    },
    onSuccess: () => {
      toast({
        title: "Appointment Cancelled",
        description: "Your appointment has been cancelled successfully.",
      });
      queryClient.invalidateQueries({ queryKey: ["/api/appointments"] });
      queryClient.invalidateQueries({ queryKey: ["/api/patient/dashboard"] });
      setCancelDialogOpen(false);
      setSelectedAppointment(null);
      setCancelReason("");
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to cancel appointment. Please try again.",
        variant: "destructive",
      });
    },
  });

  const formatFee = (fee: number) => {
    return new Intl.NumberFormat("en-LK", {
      style: "currency",
      currency: "LKR",
      minimumFractionDigits: 0,
    }).format(fee);
  };

  const getInitials = (name: string) => {
    if (!name) return "DR";
    return name.split(" ").map((n) => n[0]).join("").toUpperCase().slice(0, 2);
  };

  const getConsultationIcon = (type: string) => {
    switch (type) {
      case ConsultationType.ONLINE:
        return <Video className="h-4 w-4" />;
      case ConsultationType.HOME_VISIT:
        return <MapPin className="h-4 w-4" />;
      default:
        return <Building2 className="h-4 w-4" />;
    }
  };

  const getConsultationLabel = (type: string) => {
    switch (type) {
      case ConsultationType.ONLINE:
        return "Online";
      case ConsultationType.HOME_VISIT:
        return "Home Visit";
      default:
        return "In-Person";
    }
  };

  const canCancel = (appointment: AppointmentWithDetails) => {
    const cancelableStatuses = [AppointmentStatus.PENDING, AppointmentStatus.CONFIRMED];
    if (!cancelableStatuses.includes(appointment.status as any)) return false;

    const appointmentDateTime = parseISO(`${appointment.appointmentDate}T${appointment.appointmentTime}`);
    const now = new Date();
    const hoursUntilAppointment = (appointmentDateTime.getTime() - now.getTime()) / (1000 * 60 * 60);

    return hoursUntilAppointment > 2;
  };

  const now = new Date();
  const today = format(now, "yyyy-MM-dd");

  const upcomingAppointments = appointments.filter((apt) => {
    const aptDate = parseISO(apt.appointmentDate);
    return (
      isAfter(aptDate, now) || apt.appointmentDate === today
    ) && !["cancelled", "completed", "no_show"].includes(apt.status);
  });

  const pastAppointments = appointments.filter((apt) => {
    const aptDate = parseISO(apt.appointmentDate);
    return (
      isBefore(aptDate, now) && apt.appointmentDate !== today
    ) || ["completed", "cancelled", "no_show"].includes(apt.status);
  });

  const filterAppointments = (appointmentList: AppointmentWithDetails[]) => {
    return appointmentList.filter((apt) => {
      const matchesSearch =
        searchQuery === "" ||
        apt.doctor?.user?.fullName?.toLowerCase().includes(searchQuery.toLowerCase()) ||
        apt.hospital?.name?.toLowerCase().includes(searchQuery.toLowerCase());

      const matchesStatus = statusFilter === "all" || apt.status === statusFilter;
      const matchesType = typeFilter === "all" || apt.consultationType === typeFilter;

      return matchesSearch && matchesStatus && matchesType;
    });
  };

  const filteredUpcoming = filterAppointments(upcomingAppointments);
  const filteredPast = filterAppointments(pastAppointments);

  if (isLoading) {
    return <LoadingPage message="Loading appointments..." />;
  }

  if (isError) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] gap-4">
        <AlertCircle className="h-12 w-12 text-destructive" />
        <p className="text-muted-foreground">Failed to load appointments. Please try again.</p>
        <Button onClick={() => window.location.reload()}>Retry</Button>
      </div>
    );
  }

  const AppointmentCard = ({ appointment }: { appointment: AppointmentWithDetails }) => (
    <Card 
      className="hover-elevate cursor-pointer"
      onClick={() => {
        setSelectedAppointment(appointment);
        setDetailsDialogOpen(true);
      }}
      data-testid={`card-appointment-${appointment.id}`}
    >
      <CardContent className="p-4">
        <div className="flex flex-col sm:flex-row sm:items-start gap-4">
          <Avatar className="h-12 w-12 shrink-0">
            <AvatarImage src={appointment.doctor?.user?.profileImage || ""} />
            <AvatarFallback>
              {getInitials(appointment.doctor?.user?.fullName || "")}
            </AvatarFallback>
          </Avatar>

          <div className="flex-1 min-w-0">
            <div className="flex flex-col sm:flex-row sm:items-center gap-2 sm:justify-between mb-2">
              <h3 className="font-semibold truncate">
                {appointment.doctor?.user?.fullName || "Doctor"}
              </h3>
              <StatusBadge status={appointment.status} type="appointment" />
            </div>

            <div className="grid grid-cols-2 gap-2 text-sm text-muted-foreground mb-3">
              <div className="flex items-center gap-1.5">
                <Calendar className="h-3.5 w-3.5" />
                <span>{format(parseISO(appointment.appointmentDate), "MMM d, yyyy")}</span>
              </div>
              <div className="flex items-center gap-1.5">
                <Clock className="h-3.5 w-3.5" />
                <span>{appointment.appointmentTime}</span>
              </div>
              <div className="flex items-center gap-1.5 col-span-2 sm:col-span-1">
                {getConsultationIcon(appointment.consultationType)}
                <span>{getConsultationLabel(appointment.consultationType)}</span>
              </div>
              {appointment.hospital && (
                <div className="flex items-center gap-1.5 col-span-2 sm:col-span-1 truncate">
                  <Building2 className="h-3.5 w-3.5 shrink-0" />
                  <span className="truncate">{appointment.hospital.name}</span>
                </div>
              )}
            </div>

            {appointment.queueNumber && appointment.status === AppointmentStatus.CONFIRMED && (
              <Badge variant="secondary" className="mb-2">
                Queue #{appointment.queueNumber}
              </Badge>
            )}

            <div className="flex items-center justify-between">
              <span className="text-sm text-muted-foreground">
                {appointment.symptoms?.substring(0, 50)}
                {appointment.symptoms && appointment.symptoms.length > 50 ? "..." : ""}
              </span>
              <ChevronRight className="h-4 w-4 text-muted-foreground" />
            </div>
          </div>

          <div className="sm:hidden flex justify-end">
            <DropdownMenu>
              <DropdownMenuTrigger asChild onClick={(e) => e.stopPropagation()}>
                <Button variant="ghost" size="icon" data-testid={`button-menu-${appointment.id}`}>
                  <MoreVertical className="h-4 w-4" />
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end">
                <DropdownMenuItem onClick={(e) => {
                  e.stopPropagation();
                  setSelectedAppointment(appointment);
                  setDetailsDialogOpen(true);
                }}>
                  View Details
                </DropdownMenuItem>
                {canCancel(appointment) && (
                  <DropdownMenuItem 
                    className="text-destructive"
                    onClick={(e) => {
                      e.stopPropagation();
                      setSelectedAppointment(appointment);
                      setCancelDialogOpen(true);
                    }}
                  >
                    Cancel Appointment
                  </DropdownMenuItem>
                )}
              </DropdownMenuContent>
            </DropdownMenu>
          </div>

          <div className="hidden sm:flex flex-col gap-2">
            {canCancel(appointment) && (
              <Button 
                variant="ghost" 
                size="sm"
                className="text-destructive hover:text-destructive"
                onClick={(e) => {
                  e.stopPropagation();
                  setSelectedAppointment(appointment);
                  setCancelDialogOpen(true);
                }}
                data-testid={`button-cancel-${appointment.id}`}
              >
                Cancel
              </Button>
            )}
            {appointment.status === AppointmentStatus.CONFIRMED && 
             appointment.consultationType === ConsultationType.ONLINE && (
              <Button size="sm" data-testid={`button-join-${appointment.id}`}>
                <Video className="h-4 w-4 mr-1" />
                Join Call
              </Button>
            )}
          </div>
        </div>
      </CardContent>
    </Card>
  );

  const EmptyState = ({ message }: { message: string }) => (
    <Card>
      <CardContent className="flex flex-col items-center justify-center py-12">
        <Calendar className="h-12 w-12 text-muted-foreground mb-4" />
        <p className="text-muted-foreground text-center">{message}</p>
      </CardContent>
    </Card>
  );

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl md:text-3xl font-heading font-bold">My Appointments</h1>
        <p className="text-muted-foreground">View and manage your appointments</p>
      </div>

      <div className="flex flex-col sm:flex-row gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Search by doctor or hospital..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="pl-9"
            data-testid="input-search"
          />
        </div>
        <Select value={statusFilter} onValueChange={setStatusFilter}>
          <SelectTrigger className="w-full sm:w-[160px]" data-testid="select-status">
            <Filter className="h-4 w-4 mr-2" />
            <SelectValue placeholder="Status" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All Status</SelectItem>
            <SelectItem value="pending">Pending</SelectItem>
            <SelectItem value="confirmed">Confirmed</SelectItem>
            <SelectItem value="completed">Completed</SelectItem>
            <SelectItem value="cancelled">Cancelled</SelectItem>
          </SelectContent>
        </Select>
        <Select value={typeFilter} onValueChange={setTypeFilter}>
          <SelectTrigger className="w-full sm:w-[160px]" data-testid="select-type">
            <SelectValue placeholder="Type" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All Types</SelectItem>
            <SelectItem value="in_person">In-Person</SelectItem>
            <SelectItem value="online">Online</SelectItem>
            <SelectItem value="home_visit">Home Visit</SelectItem>
          </SelectContent>
        </Select>
      </div>

      <Tabs defaultValue="upcoming" className="w-full">
        <TabsList className="grid w-full grid-cols-2 max-w-[400px]">
          <TabsTrigger value="upcoming" data-testid="tab-upcoming">
            Upcoming ({upcomingAppointments.length})
          </TabsTrigger>
          <TabsTrigger value="past" data-testid="tab-past">
            Past ({pastAppointments.length})
          </TabsTrigger>
        </TabsList>

        <TabsContent value="upcoming" className="mt-6">
          {filteredUpcoming.length === 0 ? (
            <EmptyState message="No upcoming appointments. Book a new appointment to get started." />
          ) : (
            <div className="space-y-4">
              {filteredUpcoming.map((appointment) => (
                <AppointmentCard key={appointment.id} appointment={appointment} />
              ))}
            </div>
          )}
        </TabsContent>

        <TabsContent value="past" className="mt-6">
          {filteredPast.length === 0 ? (
            <EmptyState message="No past appointments found." />
          ) : (
            <div className="space-y-4">
              {filteredPast.map((appointment) => (
                <AppointmentCard key={appointment.id} appointment={appointment} />
              ))}
            </div>
          )}
        </TabsContent>
      </Tabs>

      <Dialog open={detailsDialogOpen} onOpenChange={setDetailsDialogOpen}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>Appointment Details</DialogTitle>
          </DialogHeader>
          {selectedAppointment && (
            <div className="space-y-4">
              <div className="flex items-center gap-4">
                <Avatar className="h-16 w-16">
                  <AvatarImage src={selectedAppointment.doctor?.user?.profileImage || ""} />
                  <AvatarFallback>
                    {getInitials(selectedAppointment.doctor?.user?.fullName || "")}
                  </AvatarFallback>
                </Avatar>
                <div>
                  <h3 className="font-semibold text-lg">
                    {selectedAppointment.doctor?.user?.fullName}
                  </h3>
                  <p className="text-sm text-muted-foreground">
                    {selectedAppointment.doctor?.qualifications}
                  </p>
                  <StatusBadge status={selectedAppointment.status} type="appointment" className="mt-1" />
                </div>
              </div>

              <div className="grid gap-3 text-sm">
                <div className="flex items-center gap-3 p-3 bg-muted rounded-lg">
                  <Calendar className="h-5 w-5 text-primary" />
                  <div>
                    <p className="font-medium">
                      {format(parseISO(selectedAppointment.appointmentDate), "EEEE, MMMM d, yyyy")}
                    </p>
                    <p className="text-muted-foreground">
                      {selectedAppointment.appointmentTime}
                    </p>
                  </div>
                </div>

                <div className="flex items-center gap-3 p-3 bg-muted rounded-lg">
                  {getConsultationIcon(selectedAppointment.consultationType)}
                  <div>
                    <p className="font-medium">
                      {getConsultationLabel(selectedAppointment.consultationType)}
                    </p>
                    {selectedAppointment.hospital && (
                      <p className="text-muted-foreground">{selectedAppointment.hospital.name}</p>
                    )}
                  </div>
                </div>

                {selectedAppointment.queueNumber && (
                  <div className="flex items-center gap-3 p-3 bg-muted rounded-lg">
                    <span className="h-5 w-5 flex items-center justify-center text-xs font-bold bg-primary text-primary-foreground rounded-full">
                      #
                    </span>
                    <div>
                      <p className="font-medium">Queue Number</p>
                      <p className="text-muted-foreground">{selectedAppointment.queueNumber}</p>
                    </div>
                  </div>
                )}

                <div className="p-3 bg-muted rounded-lg">
                  <p className="font-medium mb-1">Symptoms</p>
                  <p className="text-muted-foreground">{selectedAppointment.symptoms}</p>
                </div>

                {selectedAppointment.consultationNotes && (
                  <div className="p-3 bg-muted rounded-lg">
                    <p className="font-medium mb-1">Doctor's Notes</p>
                    <p className="text-muted-foreground">{selectedAppointment.consultationNotes}</p>
                  </div>
                )}

                {selectedAppointment.cancelReason && (
                  <div className="p-3 bg-destructive/10 rounded-lg">
                    <p className="font-medium mb-1 text-destructive">Cancellation Reason</p>
                    <p className="text-muted-foreground">{selectedAppointment.cancelReason}</p>
                  </div>
                )}
              </div>
            </div>
          )}
          <DialogFooter className="flex-col sm:flex-row gap-2">
            {selectedAppointment && canCancel(selectedAppointment) && (
              <Button
                variant="destructive"
                onClick={() => {
                  setDetailsDialogOpen(false);
                  setCancelDialogOpen(true);
                }}
                data-testid="button-cancel-dialog"
              >
                Cancel Appointment
              </Button>
            )}
            {selectedAppointment?.status === AppointmentStatus.CONFIRMED && 
             selectedAppointment?.consultationType === ConsultationType.ONLINE && (
              <Button data-testid="button-join-dialog">
                <Video className="h-4 w-4 mr-2" />
                Join Video Call
              </Button>
            )}
            <Button variant="outline" onClick={() => setDetailsDialogOpen(false)}>
              Close
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <Dialog open={cancelDialogOpen} onOpenChange={setCancelDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Cancel Appointment</DialogTitle>
            <DialogDescription>
              Are you sure you want to cancel this appointment? This action cannot be undone.
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            <Textarea
              placeholder="Please provide a reason for cancellation..."
              value={cancelReason}
              onChange={(e) => setCancelReason(e.target.value)}
              rows={3}
              data-testid="input-cancel-reason"
            />
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setCancelDialogOpen(false)}>
              Keep Appointment
            </Button>
            <Button
              variant="destructive"
              onClick={() => {
                if (selectedAppointment) {
                  cancelMutation.mutate({ id: selectedAppointment.id, reason: cancelReason });
                }
              }}
              disabled={cancelMutation.isPending}
              data-testid="button-confirm-cancel"
            >
              {cancelMutation.isPending ? "Cancelling..." : "Cancel Appointment"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

